public class Conv{
  public Conv(int a) {
    this.a = a;
  }
  int func() {
    int b = 1;
    for (int i=1; i<a; i++){
      b = a * i + b;
    }
    return a + b;
  }
  int a;
}

public static void main(String[] args){
  Conv obj = new Conv(3);
  obj.a = 5;
  int b = obj.func();
  System.out.print(obj.a + b);
}
